const items = $input.all();
const results = [];

for (const item of items) {
  let texto = item.json.response || "";
  let minuta = "No se pudo extraer el texto de la minuta";
  let data_json = {}; 

  if (texto.includes("---MINUTA---")) {
      const splitMinuta = texto.split("---MINUTA---")[1];
      if (splitMinuta) {
          if (splitMinuta.includes("---JSON---")) {
              minuta = splitMinuta.split("---JSON---")[0].trim();
          } else {
              minuta = splitMinuta.trim();
          }
      }
  } else {
      minuta = texto.split("{")[0].trim();
  }

  try {
      let raw_texto = texto;
      if (raw_texto.includes("```json")) {
          const partes = raw_texto.split("```json");
          if (partes.length > 1) raw_texto = partes[1].split("```")[0];
      }
      const firstBrace = raw_texto.indexOf("{");
      const lastBrace = raw_texto.lastIndexOf("}");

      if (firstBrace !== -1 && lastBrace !== -1) {
          data_json = JSON.parse(raw_texto.substring(firstBrace, lastBrace + 1));
      } else {
          data_json = { "error": "No JSON found" };
      }
  } catch (e) {
      data_json = { "error": String(e) };
  }

  results.push({
    json: {
      minuta: minuta,
      json: data_json,
      raw_llm_text: texto
    }
  });
}

return results;
